function ConfirmDialog({
  isOpen,
  title,
  description,
  confirmLabel,
  cancelLabel = "Cancel",
  onConfirm,
  onCancel,
  isSubmitting = false,
  tone = "default"
}) {
  if (!isOpen) {
    return null;
  }

  return (
    <div className="preview-backdrop" role="presentation">
      <div className="preview-modal confirm-modal" role="dialog" aria-modal="true" aria-labelledby="confirm-title">
        <div className="preview-header">
          <div>
            <h2 id="confirm-title">{title}</h2>
            <p className="panel-copy">{description}</p>
          </div>
          <button type="button" className="ghost-button" onClick={onCancel} disabled={isSubmitting}>
            Close
          </button>
        </div>

        <div className="preview-body">
          <div className="button-row confirm-actions">
            <button type="button" className="secondary-button" onClick={onCancel} disabled={isSubmitting}>
              {cancelLabel}
            </button>
            <button
              type="button"
              className={tone === "danger" ? "danger-button" : "primary-button"}
              onClick={onConfirm}
              disabled={isSubmitting}
            >
              {isSubmitting ? "Working..." : confirmLabel}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ConfirmDialog;
